import type { RouteStopItem } from "@gunjo/ui"

/** 配送状況の段階。 */
export type TrackingStageStatus = "completed" | "current" | "pending"

export interface TrackingStage {
  id: string
  /** 集荷済 / 輸送中 / 配達店到着 / 配達中 / 配達完了 */
  title: string
  /** 営業所・現在地など */
  place: string
  status: TrackingStageStatus
  /** 実績または予定の日時 (例 "6/29 14:20") */
  stamp?: string
}

export interface Shipment {
  /** 送り状番号（問い合わせ番号） */
  trackingNo: string
  /** お届け先 */
  destination: string
  /** お届け先 都道府県・市区 */
  destinationArea: string
  /** 品目 */
  item: string
  /** 個数 */
  pieces: number
  /** 便種別 */
  service: "特積" | "路線便" | "チャーター" | "宅配便"
  /** 現在の状況ラベル */
  statusLabel:
    | "集荷待ち"
    | "集荷済"
    | "輸送中"
    | "配達店到着"
    | "配達中"
    | "配達完了"
    | "不在持戻り"
  /** お届け予定 (ETA) */
  eta: string
  /** 追跡タイムライン */
  stages: TrackingStage[]
}

export interface HistoryRow {
  trackingNo: string
  destination: string
  /** 受付/出荷日 */
  date: string
  /** 運賃（税込） */
  fare: number
