export type PaymentValue = "moto" /* 元払い */ | "chaku" /* 着払い */

// ---- 見積（運賃）計算: server-safe な純関数 ----

export interface QuoteInput {
  vehicle: VehicleValue
  pieces: number
  /** チャーターや時間帯指定など割増の有無 */
  timeBand: TimeBandValue
  payment: PaymentValue
}

export interface QuoteLine {
  label: string
  amount: number
  kind?: "add" | "subtract"
  note?: string
}

export interface Quote {
  lines: QuoteLine[]
  total: number
}

/**
 * 概算運賃の見積。基本運賃 + 個建料金 + 時間帯指定料 + 燃料サーチャージ −
 * Web申込割引、消費税。純関数なので Server Component から直接呼べる。
 */
export function estimateQuote(input: QuoteInput): Quote {
  const vehicle = VEHICLE_OPTIONS.find((v) => v.value === input.vehicle)
  const base = vehicle?.base ?? 0

  const pieceFee = Math.max(0, input.pieces - 1) * 350
  const timeBandFee = input.timeBand === "am" ? 0 : 550
  const fuelSurcharge = Math.round(base * 0.08)
  const webDiscount = -Math.round(base * 0.05)

  const subtotal = base + pieceFee + timeBandFee + fuelSurcharge + webDiscount
  const tax = Math.round(subtotal * 0.1)
  const total = subtotal + tax

  const lines: QuoteLine[] = [
    { label: "基本運賃", amount: base, note: vehicle?.title },
    { label: "個建料金", amount: pieceFee, note: `${input.pieces}個（1個目無料）` },
    {
      label: "時間帯指定料",
      amount: timeBandFee,
      note: input.timeBand === "am" ? "午前中（無料）" : undefined,
    },
    { label: "燃料サーチャージ", amount: fuelSurcharge, note: "基本運賃の8%" },
    { label: "Web申込割引", amount: webDiscount, kind: "subtract" },
    { label: "消費税（10%）", amount: tax },
  ]

  return { lines, total }
}

