/** RouteStops 用にトラッキング段階をマッピング（client 側で title/meta を組み立てる）。 */
export function toRouteStops(stages: TrackingStage[]): RouteStopItem[] {
  return stages.map((st) => ({
    id: st.id,
    title: st.title,
    description: st.place,
    status: st.status === "completed" ? "completed" : st.status === "current" ? "current" : "pending",
    // 日付込みのスタンプは plannedTime("HH:MM") に収まらないので meta に置く。
    meta: st.stamp,
  }))
}

