/** 月ごとの「件数・合計金額（キャンセル除く）」サマリ。 */
export function monthSummary(rows: HistoryRow[]): { count: number; total: number } {
  const billable = rows.filter((r) => r.status !== "キャンセル")
  return {
    count: rows.length,
    total: billable.reduce((sum, r) => sum + r.fare, 0),
  }
}

/** 状況ラベル → Badge variant。色だけに頼らないようラベルと併用する。 */
export type StatusBadgeVariant = "secondary" | "info" | "success" | "warning" | "destructive"

export function statusVariant(label: Shipment["statusLabel"]): StatusBadgeVariant {
  switch (label) {
    case "配達完了":
      return "success"
    case "輸送中":
    case "配達中":
      return "info"
    case "配達店到着":
    case "集荷済":
      return "secondary"
    case "集荷待ち":
      return "warning"
    case "不在持戻り":
      return "destructive"
    default:
      return "secondary"
  }
}

"use client"

import * as React from "react"
