} from "@gunjo/ui"

import {
  activeShipments,
  historyMonths,
  monthSummary,
  statusVariant,
  toRouteStops,
  estimateQuote,
  TIME_BANDS,
  VEHICLE_OPTIONS,
  type Shipment,
  type TimeBandValue,
  type VehicleValue,
  type PaymentValue,
} from "./data"

type Tab = "track" | "pickup" | "history" | "notify"

const TAB_OPTIONS = [
  { value: "track", label: "貨物追跡" },
  { value: "pickup", label: "集荷依頼" },
  { value: "history", label: "履歴" },
  { value: "notify", label: "通知" },
] as const

export function ShipperPortal() {
  const [tab, setTab] = React.useState<Tab>("track")
  const [selectedTracking, setSelectedTracking] = React.useState<string>(
    activeShipments[0].trackingNo
  )

  const selected =
    activeShipments.find((s) => s.trackingNo === selectedTracking) ?? activeShipments[0]

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-background">
      <PageHeader
        title="マルツバ運輸 配送ポータル"
        subtitle="荷主さま専用 / 株式会社サンプル商事"
        leading={
          <span className="inline-flex size-9 items-center justify-center rounded-md bg-primary/10 text-primary">
            <IconTruckDelivery className="size-5" aria-hidden="true" />
          </span>
        }
        actions={
          <Button
            variant="ghost"
            size="icon"
            aria-label="お知らせ"
            onClick={() => setTab("notify")}
          >
            <IconBell className="size-5" aria-hidden="true" />
          </Button>
        }
      />

      {/* タブ切替（貨物追跡 / 集荷依頼 / 履歴 / 通知） */}
      <div className="sticky top-14 z-20 border-b border-border bg-background/95 px-3 py-2 backdrop-blur">
        <SegmentedControl
          aria-label="ポータルのセクション"
          options={TAB_OPTIONS as unknown as { value: string; label: string }[]}
          value={tab}
          onValueChange={(v) => setTab(v as Tab)}
          size="lg"
        />
      </div>

      <main className="flex-1 px-3 py-4 pb-28">
        {tab === "track" ? (
          <TrackPanel selected={selected} onSelect={setSelectedTracking} selectedNo={selectedTracking} />
        ) : tab === "pickup" ? (
          <PickupPanel />
        ) : tab === "history" ? (
          <HistoryPanel />
        ) : (
          <NotifyPanel />
        )}
      </main>

      <BottomActionBar
        maxWidth="md"
        actions={
          tab === "pickup" ? (
            <Button size="xl" className="w-full">
              この内容で集荷を依頼する
            </Button>
          ) : (
            <Button size="xl" className="w-full" onClick={() => setTab("pickup")}>
              集荷を依頼する
            </Button>
          )
        }
      >
        {tab === "pickup" ? (
          <span className="text-xs text-muted-foreground">入力内容を確認のうえご依頼ください</span>
        ) : (
          <div className="flex flex-col">
            <span className="text-xs text-muted-foreground">追跡中の貨物</span>
            <span className="text-sm font-semibold text-foreground tabular-nums">
              {activeShipments.length}件 輸送中
            </span>
          </div>
        )}
