          <span className="text-xs text-muted-foreground tabular-nums">
            {activeShipments.length}件
          </span>
        </div>
        <div className="flex flex-col gap-2">
          {activeShipments.map((s) => (
            <ListCard
              key={s.trackingNo}
              onSelect={() => onSelect(s.trackingNo)}
              selected={s.trackingNo === selectedNo}
              leading={
                <span className="inline-flex size-9 items-center justify-center rounded-full bg-muted text-muted-foreground">
                  <IconTruckDelivery className="size-5" aria-hidden="true" />
                </span>
              }
              title={s.destination}
              description={
                <span className="tabular-nums">
                  送り状 {s.trackingNo} ・ {s.item}
                </span>
              }
              tags={
                <>
                  <Badge variant="secondary">{s.service}</Badge>
                  <Badge variant="info" icon={<IconMapPin />}>
                    {s.destinationArea}
                  </Badge>
                </>
              }
              status={<Badge variant={statusVariant(s.statusLabel)}>{s.statusLabel}</Badge>}
              meta={<span>お届け {s.eta}</span>}
            />
          ))}
        </div>
      </section>

      {/* 選択した送り状の追跡タイムライン */}
      <Card>
        <CardHeader>
          <div className="flex items-start justify-between gap-2">
            <div className="min-w-0">
              <CardTitle as="h2" className="text-base">
                輸送状況
              </CardTitle>
              <p className="mt-1 truncate text-sm text-muted-foreground tabular-nums">
                送り状 {selected.trackingNo}
              </p>
            </div>
            <Badge variant={statusVariant(selected.statusLabel)}>{selected.statusLabel}</Badge>
          </div>
        </CardHeader>
        <CardContent className="flex flex-col gap-4">
          {/* お届け予定（ETA） */}
          <div className="flex items-center gap-2 rounded-lg bg-muted/60 px-3 py-2">
            <IconCalendarEvent className="size-5 shrink-0 text-primary" aria-hidden="true" />
            <div className="flex flex-col">
              <span className="text-xs text-muted-foreground">お届け予定 (ETA)</span>
              <span className="text-sm font-semibold text-foreground">{selected.eta}</span>
            </div>
          </div>

          {/* 段階タイムライン：集荷済 → 輸送中 → 配達店到着 → 配達中 → 配達完了 */}
          <RouteStops
            stops={toRouteStops(selected.stages)}
            statusLabels={{ pending: "未", current: "現在", completed: "済" }}
            hideTimes
            aria-label="配送状況の段階"
          />

          <Separator />

          <div className="flex flex-wrap gap-2">
            <Button variant="outline" size="sm">
              再配達を依頼
            </Button>
            <Button variant="outline" size="sm">
              配達日を変更
            </Button>
            <Button variant="ghost" size="sm">
              受け取り場所を変更
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}

/* ───────────────────────── 集荷依頼フォーム ───────────────────────── */

function PickupPanel() {
  const [pickupDate, setPickupDate] = React.useState<Date | undefined>(undefined)
  const [timeBand, setTimeBand] = React.useState<TimeBandValue>("am")
  const [vehicle, setVehicle] = React.useState<VehicleValue>("2t")
  const [payment, setPayment] = React.useState<PaymentValue>("moto")
  const [pieces, setPieces] = React.useState<number>(1)

  const quote = estimateQuote({ vehicle, pieces, timeBand, payment })

  const steps = [
    { label: "区間", state: "completed" as const },
    { label: "荷物", state: "current" as const },
    { label: "日時", state: "upcoming" as const },
    { label: "確認", state: "upcoming" as const },
