        <Input label="集荷先" placeholder="東京都江東区青海2-4-32 サンプル倉庫" defaultValue="東京都江東区青海2-4-32 サンプル倉庫" />
        <Input label="お届け先" placeholder="千葉県千葉市美浜区中瀬1-3" />
      </FieldGroup>

      {/* 品目 / 個数・重量 */}
      <FieldGroup title="荷物">
        <Input label="品目" placeholder="例：飲料（PETボトル）" />
        <div className="grid grid-cols-2 gap-3">
