            label="個数"
            layout="stepper"
            min={1}
            max={999}
            value={pieces}
            onValueChange={setPieces}
          />
          <Input label="重量 (kg)" type="number" inputMode="numeric" placeholder="320" />
        </div>
        <Textarea label="備考（才数・パレット枚数など）" placeholder="パレット2枚 / 才数 8才" />
      </FieldGroup>

      {/* 希望集荷日時：日付 + 時間帯 */}
      <FieldGroup title="希望集荷日時">
        <div className="flex flex-col gap-1.5">
          <span className="text-sm font-medium leading-none text-foreground">希望集荷日</span>
