            value={pickupDate}
            onValueChange={setPickupDate}
            placeholder="日付を選択"
            calendarLabel="希望集荷日"
          />
        </div>
        <div className="flex flex-col gap-1.5">
          <span className="text-sm font-medium leading-none text-foreground">時間帯指定</span>
          {/* time-band は TimePicker(HH:mm) では表せないので Select で時間帯を選ぶ */}
