              <option key={b.value} value={b.value}>
                {b.label}
                {b.hint ? `（${b.hint}）` : ""}
              </option>
            ))}
          </Select>
        </div>
      </FieldGroup>

      {/* 車種：価格つき選択カード */}
      <FieldGroup title="車種">
        <RadioCardGroup
          value={vehicle}
          onValueChange={(v) => setVehicle(v as VehicleValue)}
          aria-label="車種"
          className="grid gap-2"
        >
          {VEHICLE_OPTIONS.map((v) => (
            <RadioCard
              key={v.value}
              value={v.value}
              title={v.title}
              description={v.description}
              price={
                <span className="tabular-nums">
                  {formatCurrency(v.base)}
                  <span className="text-xs font-normal text-muted-foreground">〜</span>
                </span>
              }
            />
          ))}
        </RadioCardGroup>
      </FieldGroup>

      {/* 支払い：元払い / 着払い */}
      <FieldGroup title="運賃支払い">
        <SegmentedControl
          aria-label="運賃の支払い方法"
          options={[
            { value: "moto", label: "元払い" },
            { value: "chaku", label: "着払い" },
          ]}
          value={payment}
          onValueChange={(v) => setPayment(v as PaymentValue)}
          size="lg"
        />
      </FieldGroup>

      {/* 運賃見積 */}
      <Card>
        <CardHeader>
          <CardTitle as="h2" className="text-base">
            運賃の概算見積
          </CardTitle>
        </CardHeader>
        <CardContent>
          <AmountBreakdown
            lines={quote.lines}
            total={{ label: "概算運賃（税込）", amount: quote.total, tone: "neutral" }}
            formula="基本運賃 ＋ 個建料金 ＋ 時間帯指定料 ＋ 燃料サーチャージ − Web申込割引 ＋ 消費税"
          />
          <p className="mt-3 text-xs text-muted-foreground">
            ※ 概算です。距離・地区・実重量により確定運賃は変動します。
            {payment === "chaku" ? "着払いの場合はお届け先でのお支払いとなります。" : ""}
          </p>
        </CardContent>
      </Card>
    </form>
  )
}

function FieldGroup({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <section className="flex flex-col gap-3">
      <h2 className="text-sm font-semibold text-foreground">{title}</h2>
      {children}
    </section>
  )
}

